        .toolbar { display: flex; align-items: center; gap: 8px; padding: 10px 16px; background: var(--surface); border-bottom: 1px solid var(--border); }
        .toolbar input[type="file"] { display: none; }
        .toolbar label, .toolbar button { background: var(--border); color: var(--text); border: none; padding: 6px 14px; border-radius: 6px; cursor: pointer; font-size: 0.85em; }
        .toolbar label:hover, .toolbar button:hover { background: var(--surface-hover); }
        .toolbar .title { font-weight: 600; margin-right: auto; font-size: 1.1em; }

        .summary-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 12px; margin-bottom: 24px; }
        .summary-card { background: var(--surface); border: 1px solid var(--border); border-radius: 10px; padding: 16px; text-align: center; }
        .summary-card .value { font-size: 2em; font-weight: 700; color: var(--accent); }
        .summary-card .label { font-size: 0.82em; color: var(--text-muted); margin-top: 4px; }

        .charts-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(420px, 1fr)); gap: 16px; margin-bottom: 24px; }
        .chart-card { background: var(--surface); border: 1px solid var(--border); border-radius: 10px; padding: 16px; }
        .chart-card h3 { color: var(--accent); font-size: 0.95em; margin-bottom: 12px; }
        .chart-card canvas { width: 100%; height: 240px; }

        .table-section { background: var(--surface); border: 1px solid var(--border); border-radius: 10px; padding: 16px; margin-bottom: 24px; }
        .table-section h3 { color: var(--accent); font-size: 0.95em; margin-bottom: 12px; }
        .stats-table { width: 100%; border-collapse: collapse; font-size: 0.85em; }
        .stats-table th, .stats-table td { padding: 6px 10px; border-bottom: 1px solid var(--border); text-align: left; }
        .stats-table th { color: var(--text-muted); font-weight: 600; }
        .stats-table tr:hover { background: var(--surface-hover); }
        .stats-table .num { text-align: right; font-family: 'SF Mono', monospace; color: var(--accent); }
        .stats-table .bar-cell { width: 120px; }
        .stats-table .bar-bg { background: var(--border); border-radius: 3px; height: 8px; }
        .stats-table .bar-fill { background: var(--accent); border-radius: 3px; height: 8px; }

        .components-list { display: flex; flex-wrap: wrap; gap: 8px; }
        .comp-badge { background: var(--bg); border: 1px solid var(--border); border-radius: 6px; padding: 4px 10px; font-size: 0.82em; }
        .comp-badge .comp-size { color: var(--accent); font-weight: 600; }

        .empty-state { text-align: center; padding: 80px 20px; color: var(--text-muted); }
        .empty-state h2 { color: var(--text); margin-bottom: 12px; }

        .export-btn { background: var(--green) !important; color: #000 !important; font-weight: 600; }

        @media (max-width: 900px) {
            .charts-grid { grid-template-columns: 1fr; }
            .summary-grid { grid-template-columns: repeat(2, 1fr); }
        }
    </style>
</head>
